    auto unionSets = [&](long long x, long long y) {
        long long rootX = find(x);
        long long rootY = find(y);
        if (rootX == rootY) return false;
        if (rank[rootX] < rank[rootY]) {
            parent[rootX] = rootY;
        } else {
            parent[rootY] = rootX;
            if (rank[rootX] == rank[rootY]) {
                rank[rootX]++;
            }
        }
        return true;
    };

    // Initialize parent array
    for (long long i = 0; i < n; ++i) {
        parent[i] = i;
    }

    // Process edges in order of increasing time
    long long result = 0;
    long long components = n; // Initially, each node is its own component

    for (auto& edge : edges) {
        long long u = edge[0];
        long long v = edge[1];
        long long time = edge[2];

        // If the nodes are in different sets, union them
        if (unionSets(u, v)) {
            // After union, the number of components decreases by 1
            components--;
        }

        // Check if we have at least k components
        if (components >= k) {
            result = time;
            break;
        }
    }

    return result;
}
